function num2persian(n) {
    // ترجمه اعداد 0-9
    var units = ["صفر", "یک", "دو", "سه", "چهار", "پنج", "شش", "هفت", "هشت", "نه"];
    // ترجمه اعداد 10-19
    var teens = ["ده", "یازده", "دوازده", "سیزده", "چهارده", "پانزده", "شانزده", "هفده", "هجده", "نوزده"];
    // ترجمه اعداد 20, 30, ..., 90
    var tens = ["", "", "بیست", "سی", "چهل", "پنجاه", "شصت", "هفتاد", "هشتاد", "نود"];
    // ترجمه اعداد 100, 200, ..., 900
    var hundreds = ["", "صد", "دویست", "سیصد", "چهارصد", "پانصد", "ششصد", "هفتصد", "هشتصد", "نهصد"];
    // نام مقادیر بزرگ (هزار، میلیون و ...)
    var thousands = ["", "هزار", "میلیون", "میلیارد", "تریلیون"]; // می توان مقادیر بیشتری افزود

    // حذف فاصله های اضافی و تبدیل عدد به رشته
    var num = String(n).trim();

    // مدیریت اعداد منفی
    var isNegative = false;
    if (num.startsWith("-")) {
        isNegative = true;
        num = num.substring(1);
    }

    // مدیریت عدد صفر
    if (num === "0") {
        return "صفر";
    }

    var parts = []; // آرایه ای برای نگهداری بخش های ترجمه شده عدد (مثلا: "هشتصد", "سی و هشت")
    var chunkIndex = 0; // اندیس برای بخش های هزار، میلیون و ...

    // پردازش عدد در تکه های سه رقمی از راست به چپ
    while (num.length > 0) {
        var chunk = num.slice(-3); // گرفتن سه رقم آخر
        num = num.slice(0, -3); // حذف سه رقم آخر از رشته اصلی

        var chunkNum = parseInt(chunk, 10);
        var chunkStr = "";

        if (chunkNum > 0) {
            var hundred = Math.floor(chunkNum / 100);
            var rest = chunkNum % 100;

            // پردازش صدگان
            if (hundred > 0) {
                chunkStr += hundreds[hundred];
                if (rest > 0) {
                    chunkStr += " و ";
                }
            }

            // پردازش دهگان و یکان
            if (rest > 0) {
                if (rest < 10) { // اعداد 1 تا 9
                    chunkStr += units[rest];
                } else if (rest < 20) { // اعداد 10 تا 19
                    chunkStr += teens[rest - 10];
                } else { // اعداد 20 تا 99
                    var ten = Math.floor(rest / 10);
                    var unit = rest % 10;
                    chunkStr += tens[ten];
                    if (unit > 0) {
                        chunkStr += " و " + units[unit];
                    }
                }
            }

            // اضافه کردن نام مقدار بزرگ (هزار، میلیون و ...)
            if (thousands[chunkIndex]) {
                // اگر بخش صدگان و بقیه صفر باشند، ولی خود عدد بخش هزار باشد
                if (chunkStr === "") { // این حالت نباید رخ دهد با chunkNum > 0
                  // این خط برای اطمینان است، معمولا بخش صدگان و بقیه باعث می شود chunkStr خالی نباشد
                } else {
                   chunkStr += " " + thousands[chunkIndex];
                }
            }
            parts.push(chunkStr);
        }
        chunkIndex++; // رفتن به بخش بعدی (هزار، میلیون و ...)
    }

    // ترکیب نهایی بخش ها (به ترتیب از بزرگترین به کوچکترین)
    var result = parts.reverse().join(" و ");

    // اضافه کردن "منفی" اگر عدد اصلی منفی بوده است
    if (isNegative) {
        return "منفی " + result;
    } else {
        return result;
    }
}